INSERT INTO boards (
    board_code, board_name, description, is_active, sort_order
) VALUES (
    #{boardCode}, #{boardName}, #{description},
    COALESCE(#{isActive}, TRUE), COALESCE(#{sortOrder}, 0)
)

INSERT INTO board_posts (
    board_code, title, content, author_id, author_name, is_pinned, is_active
) VALUES (
    #{boardCode}, #{title}, #{content}, #{authorId}, #{authorName},
    COALESCE(#{isPinned}, FALSE), COALESCE(#{isActive}, TRUE)
)
